// Post to Meta Threads (single long post + optional image).
// Requires n8n Variables: THREADS_USER_ID, THREADS_ACCESS_TOKEN.

const userId = $vars.THREADS_USER_ID;
const accessToken = $vars.THREADS_ACCESS_TOKEN;
if (!userId || !accessToken) throw new Error('Missing THREADS_USER_ID or THREADS_ACCESS_TOKEN');

const item = $input.item.json;
const text = item.posts.threads.text;
const imageUrl = item.image_url;
const authHeader = { Authorization: `Bearer ${accessToken}` };

// 1. Create media container
const containerBody = { media_type: imageUrl ? 'IMAGE' : 'TEXT', text };
if (imageUrl) containerBody.image_url = imageUrl;

const container = await $helpers.httpRequest({
  method: 'POST',
  url: `https://graph.threads.net/v1.0/${userId}/threads`,
  headers: authHeader,
  body: containerBody,
  json: true,
});
const creationId = container.id;

// 2. Publish — retry up to 6 times if the image container isn't ready yet.
//    Each attempt first probes the container status via GET, which provides natural backoff without timers.
let publishRes;
let lastErr;
for (let attempt = 0; attempt < 6; attempt++) {
  // Probe container readiness via GET; round-trip serves as backoff
  if (attempt > 0) {
    try {
      await $helpers.httpRequest({
        method: 'GET',
        url: `https://graph.threads.net/v1.0/${creationId}`,
        headers: authHeader,
        qs: { fields: 'status,error_message' },
        json: true,
      });
    } catch (_) { /* ignore probe failures */ }
  }
  try {
    publishRes = await $helpers.httpRequest({
      method: 'POST',
      url: `https://graph.threads.net/v1.0/${userId}/threads_publish`,
      headers: authHeader,
      qs: { creation_id: creationId },
      json: true,
    });
    break;
  } catch (err) {
    lastErr = err;
    // If not ready yet, keep looping; for other errors, stop immediately.
    const msg = String(err?.message || err);
    if (!msg.includes('not ready') && !msg.includes('Media ID is not available')) throw err;
  }
}
if (!publishRes) throw lastErr || new Error('Threads publish failed after retries');

return {
  json: {
    channel: 'threads',
    slug: item.slug,
    post_id: publishRes.id,
    url: `https://www.threads.net/@me/post/${publishRes.id}`,
  },
};

// Post Bluesky thread (array of posts, chained as replies).
// Requires n8n Variables: BSKY_HANDLE (e.g. alecfoster.bsky.social), BSKY_APP_PASSWORD.

const handle = $vars.BSKY_HANDLE;
const appPassword = $vars.BSKY_APP_PASSWORD;
if (!handle || !appPassword) throw new Error('Missing BSKY_HANDLE or BSKY_APP_PASSWORD');

const item = $input.item.json;
const thread = item.posts.bluesky.thread; // array of strings
const imageUrl = item.image_url;

// 1. Login
const session = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://bsky.social/xrpc/com.atproto.server.createSession',
  body: { identifier: handle, password: appPassword },
  json: true,
});
const { accessJwt, did } = session;
const auth = { Authorization: `Bearer ${accessJwt}` };

// 2. Upload image once (attached to first post only)
let imageBlob = null;
if (imageUrl) {
  const imgRes = await $helpers.httpRequest({ method: 'GET', url: imageUrl, encoding: 'arraybuffer', returnFullResponse: true });
  const mime = imgRes.headers['content-type'] || 'image/png';
  const upload = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://bsky.social/xrpc/com.atproto.repo.uploadBlob',
    headers: { ...auth, 'Content-Type': mime },
    body: imgRes.body,
    json: true,
  });
  imageBlob = upload.blob;
}

// 3. Post thread
const postedRefs = [];
let root = null;
let parent = null;

for (let i = 0; i < thread.length; i++) {
  const text = thread[i];
  const record = {
    $type: 'app.bsky.feed.post',
    text,
    createdAt: new Date().toISOString(),
    langs: ['en'],
  };
  if (i === 0 && imageBlob) {
    record.embed = {
      $type: 'app.bsky.embed.images',
      images: [{ alt: '', image: imageBlob }],
    };
  }
  if (parent) {
    record.reply = { root, parent };
  }
  const res = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://bsky.social/xrpc/com.atproto.repo.createRecord',
    headers: auth,
    body: { repo: did, collection: 'app.bsky.feed.post', record },
    json: true,
  });
  const ref = { uri: res.uri, cid: res.cid };
  postedRefs.push(ref);
  if (i === 0) root = ref;
  parent = ref;
}

const firstRkey = postedRefs[0].uri.split('/').pop();
return {
  json: {
    channel: 'bluesky',
    slug: item.slug,
    posts: postedRefs,
    url: `https://bsky.app/profile/${handle}/post/${firstRkey}`,
  },
};
